import { Routes, Route } from "react-router-dom";
import HomePage from "./Pages/HomePage/HomePage";
import AboutUs from "./Pages/AboutUs/AboutUs";
import ContactUs from "./Pages/ContactUs/ContactUs";
import NotFound from "./Pages/NotFound/NotFound";
import ProductsDetails from "./Pages/ProductsDetails/ProductsDetails";
import Layout from "./Components/Layout";
import { ProductsData } from "./Data/ProductsData";
import { useState, useEffect } from "react";
import Loading from "./Pages/Loading"; // Import the Loading component

function App() {
  const [isLoading, setIsLoading] = useState(true); // Track loading state

  // Check if all images are loaded
  useEffect(() => {
    const images = document.images;
    let totalImages = images.length;
    let loadedImages = 0;

    const checkImageLoad = () => {
      loadedImages++;
      if (loadedImages === totalImages) {
        setIsLoading(false); // All images loaded
      }
    };

    Array.from(images).forEach((img) => {
      if (img.complete) {
        checkImageLoad();
      } else {
        img.onload = checkImageLoad;
      }
    });
  }, []); // Only run once when the component mounts

  return (
    <div>
      {isLoading ? ( // Show loading screen while images are loading
        <Loading />
      ) : (
        <Routes>
          <Route
            path="/"
            element={
              <Layout>
                <HomePage />
              </Layout>
            }
          />
          <Route
            path="/AboutUs"
            element={
              <Layout>
                <AboutUs />
              </Layout>
            }
          />
          <Route
            path="/ContactUs"
            element={
              <Layout>
                <ContactUs />
              </Layout>
            }
          />
          <Route path="*" element={<NotFound />} />
          <Route
            path="/Product/:ProductId"
            element={
              <Layout>
                <ProductsDetails images={ProductsData} />
              </Layout>
            }
          />
        </Routes>
      )}
    </div>
  );
}

export default App;


